import requests
from datetime import datetime, timedelta

def check_emoncms(expect,ans):
    if len(ans) != 32:
        return {
            'input_list': [
                {'ok': False, 'msg': 'Votre clé d\'API doit faire 32 caractères !'},
            ]
        }
    try:
        r = requests.get("https://emoncms.fr/feed/list.json?apikey=" + str(ans))
        if r.status_code == 200:
            if len(r.json()):
                feed = r.json()[0]
                if feed:
                    return {
                        'input_list': [
                            {'ok': True, 'msg': 'Bravo, au moins un flux (' + str(r.json()[0]['name']) + ') a été créé !'},
                        ]
                    }
            else:
                return {
                    'input_list': [
                        {'ok': False, 'msg': 'Il semblerait que vous n\'ayez pas créé de flux !'},
                    ]
                }
        else:
            return {
                'input_list': [
                    {'ok': False, 'msg': 'La requête HTTP a échouée !'},
                ]
            }
    except Exception as e:
        return {
            'input_list': [
                {'ok': True, 'msg': 'Vos sources ont été créées il y a plus de 10 minutes !'},
            ]
        }
